import React from 'react';

const Projects = () => {
  const projects = [
    {
      id: 1,
      title: 'Web Application System',
      description: 'A comprehensive web application with modern UI/UX, responsive design, and robust backend functionality.',
      category: 'Web Development',
      image: '/images/View Project/web application system.png',
      technologies: ['React', 'Node.js', 'MongoDB']
    },
    {
      id: 2,
      title: 'Data Analytics and Power BI',
      description: 'Interactive dashboards and data visualization solutions for business intelligence and analytics.',
      category: 'Data Analytics',
      image: '/images/View Project/Data Analytics and power bi.png',
      technologies: ['Power BI', 'SQL', 'Python']
    },
    {
      id: 3,
      title: 'Intelligent Fraud Detection',
      description: 'AI-powered fraud detection system that identifies and prevents fraudulent activities in real-time.',
      category: 'AI/ML',
      image: '/images/View Project/intelligent fraud system.png',
      technologies: ['Python', 'TensorFlow', 'Scikit-learn']
    }
  ];

  return (
    <div>
      {/* Projects Hero */}
      <section className="section-padding" style={{ background: 'linear-gradient(135deg, #0F172A 0%, #1E293B 100%)', color: 'white', textAlign: 'center' }}>
        <div className="container">
          <h1>My Projects</h1>
          <p>Explore my latest work and technical achievements</p>
        </div>
      </section>

      {/* Projects Grid */}
      <section className="section-padding">
        <div className="container">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {projects.map(project => (
              <div key={project.id} className="group bg-white dark:bg-gray-800 rounded-xl shadow-lg overflow-hidden transition-all duration-300 hover:-translate-y-2 hover:shadow-xl">
                <div className="relative overflow-hidden h-64">
                  <img 
                    src={project.image} 
                    alt={project.title} 
                    className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-end p-6">
                    <div className="space-x-2">
                      <span className="inline-block px-3 py-1 text-xs font-medium text-white bg-primary-600 rounded-full">
                        {project.category}
                      </span>
                    </div>
                  </div>
                </div>
                <div className="p-6">
                  <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-2">{project.title}</h3>
                  <p className="text-gray-600 dark:text-gray-300 mb-4">{project.description}</p>
                  <div className="flex flex-wrap gap-2 mb-4">
                    {project.technologies.map((tech, index) => (
                      <span key={index} className="px-2 py-1 text-xs bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 rounded">
                        {tech}
                      </span>
                    ))}
                  </div>
                  <div className="flex space-x-3">
                    <button className="inline-flex items-center px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-lg hover:bg-gray-200 dark:bg-gray-700 dark:text-gray-200 dark:hover:bg-gray-600 transition-colors">
                      View Project
                    </button>
                    <button className="inline-flex items-center px-4 py-2 text-sm font-medium text-white bg-primary-600 rounded-lg hover:bg-primary-700 transition-colors">
                      Live Demo
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>
    </div>
  );
};

export default Projects;
